var NicoWidget = (function() {

  var AVATAR_URL = '/static/img/agents/daisy_chain.png';
  var MAX_MESSAGES = 50;
  var _panel, _messagesEl, _inputEl, _sendBtn;
  var _isOpen = false;
  var _isSending = false;

  function _getSession() {
    var s = localStorage.getItem('np_nico_session');
    if (!s) {
      s = 'guide-' + Date.now() + '-' + Math.random().toString(36).substr(2, 6);
      localStorage.setItem('np_nico_session', s);
    }
    return s;
  }

  function _getMessages() {
    try { return JSON.parse(localStorage.getItem('np_nico_messages') || '[]'); }
    catch(e) { return []; }
  }

  function _saveMessages(msgs) {
    if (msgs.length > MAX_MESSAGES) msgs = msgs.slice(-MAX_MESSAGES);
    localStorage.setItem('np_nico_messages', JSON.stringify(msgs));
  }

  function _buildDOM() {
    var widget = document.createElement('div');
    widget.id = 'nicoWidget';

    var toggle = document.createElement('button');
    toggle.id = 'nicoToggle';
    toggle.title = 'Daisy Chain \u2014 Platform Guide';
    toggle.onclick = function() { _toggle(); };

    var toggleImg = document.createElement('img');
    toggleImg.src = AVATAR_URL;
    toggleImg.alt = 'Daisy Chain';
    toggleImg.onerror = function() {
      this.style.display = 'none';
      var fb = document.createElement('span');
      fb.className = 'nico-toggle-fallback';
      fb.textContent = 'D';
      toggle.appendChild(fb);
    };
    toggle.appendChild(toggleImg);

    _panel = document.createElement('div');
    _panel.id = 'nicoPanel';

    var header = document.createElement('div');
    header.className = 'nico-header';

    var hAvatar = document.createElement('img');
    hAvatar.src = AVATAR_URL;
    hAvatar.className = 'nico-header-avatar';
    hAvatar.onerror = function() {
      var fb = document.createElement('div');
      fb.className = 'nico-header-avatar-fb';
      fb.textContent = 'D';
      this.replaceWith(fb);
    };

    var hInfo = document.createElement('div');
    hInfo.className = 'nico-header-info';
    var hName = document.createElement('div');
    hName.className = 'nico-header-name';
    hName.textContent = 'Daisy Chain';
    var hRole = document.createElement('div');
    hRole.className = 'nico-header-role';
    hRole.textContent = 'Platform Guide';
    hInfo.appendChild(hName);
    hInfo.appendChild(hRole);

    var hActions = document.createElement('div');
    hActions.className = 'nico-header-actions';

    var clearBtn = document.createElement('button');
    clearBtn.className = 'nico-header-btn';
    clearBtn.title = 'Clear conversation';
    clearBtn.onclick = _clearChat;
    var clearIcon = document.createElement('span');
    clearIcon.className = 'material-symbols-outlined';
    clearIcon.textContent = 'delete_sweep';
    clearBtn.appendChild(clearIcon);

    var closeBtn = document.createElement('button');
    closeBtn.className = 'nico-header-btn';
    closeBtn.title = 'Minimize';
    closeBtn.onclick = function() { _toggle(); };
    var closeIcon = document.createElement('span');
    closeIcon.className = 'material-symbols-outlined';
    closeIcon.textContent = 'minimize';
    closeBtn.appendChild(closeIcon);

    hActions.appendChild(clearBtn);
    hActions.appendChild(closeBtn);

    header.appendChild(hAvatar);
    header.appendChild(hInfo);
    header.appendChild(hActions);

    _messagesEl = document.createElement('div');
    _messagesEl.className = 'nico-messages';

    var inputArea = document.createElement('div');
    inputArea.className = 'nico-input-area';

    _inputEl = document.createElement('input');
    _inputEl.className = 'nico-input';
    _inputEl.type = 'text';
    _inputEl.dir = 'auto';
    _inputEl.placeholder = 'Ask about the platform...';
    _inputEl.addEventListener('keydown', function(e) {
      if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); _send(); }
    });

    _sendBtn = document.createElement('button');
    _sendBtn.className = 'nico-send';
    _sendBtn.onclick = _send;
    var sendIcon = document.createElement('span');
    sendIcon.className = 'material-symbols-outlined';
    sendIcon.textContent = 'send';
    _sendBtn.appendChild(sendIcon);

    inputArea.appendChild(_inputEl);
    inputArea.appendChild(_sendBtn);

    _panel.appendChild(header);
    _panel.appendChild(_messagesEl);
    _panel.appendChild(inputArea);

    widget.appendChild(_panel);
    widget.appendChild(toggle);
    document.body.appendChild(widget);

    var msgs = _getMessages();
    if (msgs.length === 0) {
      _showWelcome();
    } else {
      msgs.forEach(function(m) { _renderMsg(m.role, m.content); });
    }

    if (localStorage.getItem('np_nico_open') === '1') {
      _panel.classList.add('open');
      _isOpen = true;
    }
  }

  function _showWelcome() {
    var w = document.createElement('div');
    w.className = 'nico-welcome';
    var t1 = document.createTextNode("Hi! I'm ");
    var b = document.createElement('strong');
    b.textContent = 'Daisy Chain';
    var t2 = document.createTextNode(", your platform guide. Ask me anything about how to use NextPlay \u2014 where to find features, how things work, or what to do next.");
    w.appendChild(t1);
    w.appendChild(b);
    w.appendChild(t2);
    _messagesEl.appendChild(w);
  }

  function _formatAssistant(content) {
    var frag = document.createDocumentFragment();
    var lines = content.split('\n');
    var list = null;
    var listType = null;

    for (var i = 0; i < lines.length; i++) {
      var trimmed = lines[i].trim();
      if (!trimmed) {
        if (list) { frag.appendChild(list); list = null; listType = null; }
        continue;
      }
      var numMatch = trimmed.match(/^(\d+)[\.\)]\s+(.+)/);
      var bulletMatch = !numMatch && trimmed.match(/^[-\u2022\u2013\*]\s+(.+)/);

      if (numMatch) {
        if (listType !== 'ol') {
          if (list) frag.appendChild(list);
          list = document.createElement('ol');
          listType = 'ol';
        }
        var li = document.createElement('li');
        li.textContent = numMatch[2];
        list.appendChild(li);
      } else if (bulletMatch) {
        if (listType !== 'ul') {
          if (list) frag.appendChild(list);
          list = document.createElement('ul');
          listType = 'ul';
        }
        var li2 = document.createElement('li');
        li2.textContent = bulletMatch[1];
        list.appendChild(li2);
      } else {
        if (list) { frag.appendChild(list); list = null; listType = null; }
        var p = document.createElement('p');
        p.textContent = trimmed;
        frag.appendChild(p);
      }
    }
    if (list) frag.appendChild(list);
    return frag;
  }

  function _renderMsg(role, content) {
    var welcome = _messagesEl.querySelector('.nico-welcome');
    if (welcome) welcome.remove();

    var msg = document.createElement('div');
    msg.className = 'nico-msg ' + role;
    var hasHebrew = /[\u0590-\u05FF]/.test(content);
    msg.dir = hasHebrew ? 'rtl' : 'ltr';

    if (role === 'assistant') {
      msg.appendChild(_formatAssistant(content));
    } else {
      msg.textContent = content;
    }

    _messagesEl.appendChild(msg);
    _messagesEl.scrollTop = _messagesEl.scrollHeight;
    return msg;
  }

  function _toggle() {
    _isOpen = !_isOpen;
    _panel.classList.toggle('open', _isOpen);
    localStorage.setItem('np_nico_open', _isOpen ? '1' : '0');
    if (_isOpen) {
      _messagesEl.scrollTop = _messagesEl.scrollHeight;
      setTimeout(function() { _inputEl.focus(); }, 100);
    }
  }

  function _clearChat() {
    localStorage.removeItem('np_nico_messages');
    localStorage.removeItem('np_nico_session');
    _messagesEl.textContent = '';
    _showWelcome();
  }

  async function _send() {
    var msg = (_inputEl.value || '').trim();
    if (!msg || _isSending) return;

    _isSending = true;
    _sendBtn.disabled = true;
    _inputEl.value = '';

    _renderMsg('user', msg);
    var msgs = _getMessages();
    msgs.push({ role: 'user', content: msg, ts: Date.now() });
    _saveMessages(msgs);

    var typingEl = document.createElement('div');
    typingEl.className = 'nico-msg typing';
    typingEl.textContent = 'Daisy is thinking...';
    _messagesEl.appendChild(typingEl);
    _messagesEl.scrollTop = _messagesEl.scrollHeight;

    var fullResponse = '';

    try {
      var res = await fetch('/api/chat-stream', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          message: msg,
          session_id: _getSession(),
          agent: 'guide'
        })
      });

      if (!res.ok) throw new Error('API error');

      var contentType = res.headers.get('content-type') || '';

      if (contentType.includes('text/event-stream')) {
        var reader = res.body.getReader();
        var decoder = new TextDecoder();
        var buffer = '';

        typingEl.remove();
        var responseEl = document.createElement('div');
        responseEl.className = 'nico-msg assistant';
        _messagesEl.appendChild(responseEl);

        while (true) {
          var result = await reader.read();
          if (result.done) break;
          buffer += decoder.decode(result.value, { stream: true });
          var lines = buffer.split('\n');
          buffer = lines.pop();
          for (var i = 0; i < lines.length; i++) {
            var line = lines[i].trim();
            if (!line.startsWith('data: ')) continue;
            try {
              var evt = JSON.parse(line.substring(6));
              if (evt.t === 'chunk' && evt.c) {
                fullResponse += evt.c;
                responseEl.textContent = fullResponse;
                _messagesEl.scrollTop = _messagesEl.scrollHeight;
              }
            } catch(e) {}
          }
        }

        responseEl.textContent = '';
        var hasHeb = /[\u0590-\u05FF]/.test(fullResponse);
        responseEl.dir = hasHeb ? 'rtl' : 'ltr';
        responseEl.appendChild(_formatAssistant(fullResponse));
      } else {
        var data = await res.json();
        typingEl.remove();
        fullResponse = data.response || data.error || 'No response';
        _renderMsg('assistant', fullResponse);
      }
    } catch(e) {
      typingEl.remove();
      fullResponse = "Sorry, I couldn't connect. Please try again.";
      _renderMsg('assistant', fullResponse);
    }

    if (fullResponse) {
      var msgs2 = _getMessages();
      msgs2.push({ role: 'assistant', content: fullResponse, ts: Date.now() });
      _saveMessages(msgs2);
    }

    _isSending = false;
    _sendBtn.disabled = false;
    _inputEl.focus();
  }

  function init() {
    _buildDOM();
  }

  return { init: init, toggle: _toggle };
})();

document.addEventListener('DOMContentLoaded', function() {
  NicoWidget.init();
});